import asyncio
from collections import defaultdict

class Player:
    def __init__(self, player_id, position):
        self.player_id = player_id
        self.position = position

class GameServer:
    def __init__(self):
        self.players = {}
        self.clients = set()
        self.server_task = None

    async def start(self):
        self.server_task = asyncio.create_task(self.broadcast_game_state())

    async def stop(self):
        if self.server_task:
            self.server_task.cancel()
            await self.server_task

    async def handle_client_connection(self, reader, writer):
        client_id = id(writer)
        self.clients.add(client_id)

        while True:
            try:
                data = await reader.read(1024)
                if not data:
                    break
                message = data.decode()
                # Validate and process player position update
                if message.startswith("UPDATE_POSITION:"):
                    player_id, new_position = message.split(":")[1].split(",")
                    self.update_player_position(player_id, (int(new_position[0]), int(new_position[1])))
            except Exception as e:
                print(f"Error handling client {client_id}: {e}")
                break

        self.clients.remove(client_id)
        writer.close()
        await writer.wait_closed()

    def update_player_position(self, player_id, new_position):
        if player_id in self.players:
            self.players[player_id].position = new_position
            asyncio.create_task(self.broadcast_game_state())

    async def broadcast_game_state(self):
        while True:
            await asyncio.sleep(1)  # Broadcast every second
            game_state = {player.player_id: player.position for player in self.players.values()}
            for client_id, writer in list(self.clients):
                try:
                    message = f"GAME_STATE:{game_state}"
                    writer.write(message.encode())
                    await writer.drain()
                except Exception as e:
                    print(f"Error broadcasting to client {client_id}: {e}")
                    self.clients.remove(client_id)

async def main():
    server = GameServer()
    await server.start()

    # Simulate client connections
    reader, writer = await asyncio.open_connection('127.0.0.1', 8888)
    asyncio.create_task(server.handle_client_connection(reader, writer))

    try:
        await asyncio.sleep(3600)  # Run for an hour
    finally:
        await server.stop()

if __name__ == "__main__":
    asyncio.run(main())